// Example 2: Iterative Refinement Workflow
// Demonstrates breaking a complex task into steps with feedback loops

/*
=== ITERATION 1 ===
REQUEST:
"I need to add real-time notifications to our Vue.js application. 
We use Socket.IO for WebSocket connections and Pinia for state management.
The notification system should support: real-time alerts, read/unread states,
and a notification center dropdown."

// Claude's response would include initial implementation outline

/*
=== ITERATION 2 (Feedback) ===
REQUEST:
"Good start. I have a few adjustments:

1. The notification store needs to persist unread state to localStorage
2. We need to support grouping notifications by type (order, message, system)
3. Add a badge count to the app header that updates in real-time

4. Include WebSocket reconnection logic with exponential backoff

Keep the socket service pattern from /services/socketService.ts."

/*
=== ITERATION 3 (More Specific Feedback) ===
REQUEST:
"The grouping implementation needs refinement. Specifically:
- Group by date first (Today, Yesterday, Earlier)
- Then by type within each date group
- Each group should show a count badge
- The notification center should have lazy loading (20 items per page)
- Add toast notifications for high-priority items (type: 'urgent')

See /stores/userStore.ts for how we handle persistence."

*/

// Final implementation after iterations:

// stores/notificationStore.ts
import { defineStore } from 'pinia';
import { ref, computed } from 'vue';
import { io, Socket } from 'socket.io-client';

const STORAGE_KEY = 'notification_state';
const MAX_RETRIES = 5;
const BASE_RETRY_DELAY = 1000; // 1 second base delay

export interface Notification {
  id: string;
  type: 'order' | 'message' | 'system' | 'urgent';
  title: string;
  body: string;
  read: boolean;
  priority: 'normal' | 'high' | 'urgent';
  createdAt: Date;
  metadata?: Record<string, unknown>;
}

export interface GroupedNotifications {
  date: string;
  label: string;
  notifications: Notification[];
}

export const useNotificationStore = defineStore('notifications', () => {
  // State
  const notifications = ref<Notification[]>([]);
  const socket = ref<Socket | null>(null);
  const isConnected = ref(false);
  const currentPage = ref(1);
  const pageSize = 20;
  const retryCount = ref(0);

  // Computed
  const unreadCount = computed(() => 
    notifications.value.filter(n => !n.read).length
  );

  const groupedNotifications = computed<GroupedNotifications[]>(() => {
    const groups: Map<string, Notification[]> = new Map();

    // Group by date, then by type
    notifications.value.forEach(notification => {
      const dateKey = formatDateGroup(notification.createdAt);
      const typeKey = notification.type;
      const groupKey = `${dateKey}|${typeKey}`;

      if (!groups.has(groupKey)) {
        groups.set(groupKey, []);
      }
      groups.get(groupKey)!.push(notification);
    });

    // Convert to array and sort
    return Array.from(groups.entries())
      .map(([key, items]) => {
        const [date, type] = key.split('|');
        return {
          date,
          label: formatDateLabel(date),
          type,
          count: items.length,
          notifications: items.sort(
            (a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
          ),
        };
      })
      .sort((a, b) => b.date.localeCompare(a.date));
  });

  const paginatedNotifications = computed(() => {
    const start = 0;
    const end = currentPage.value * pageSize;
    return notifications.value.slice(start, end);
  });

  const hasMore = computed(() => 
    currentPage.value * pageSize < notifications.value.length
  );

  // Actions
  function initializeSocket(url: string) {
    socket.value = io(url, {
      transports: ['websocket'],
      reconnection: true,
      reconnectionAttempts: MAX_RETRIES,
      reconnectionDelay: calculateBackoffDelay(),
    });

    socket.value.on('connect', () => {
      isConnected.value = true;
      retryCount.value = 0;
      console.log('Notification socket connected');
    });

    socket.value.on('notification', (notification: Notification) => {
      notifications.value.unshift(notification);

      // Show toast for urgent notifications
      if (notification.priority === 'urgent') {
        showToast(notification);
      }
    });

    socket.value.on('disconnect', () => {
      isConnected.value = false;
    });

    socket.value.on('connect_error', () => {
      retryCount.value++;
    });
  }

  function calculateBackoffDelay(): number {
    // Exponential backoff: 1s, 2s, 4s, 8s, 16s
    return BASE_RETRY_DELAY * Math.pow(2, retryCount.value);
  }

  function formatDateGroup(date: Date): string {
    return new Date(date).toISOString().split('T')[0];
  }

  function formatDateLabel(dateStr: string): string {
    const today = new Date().toISOString().split('T')[0];
    const yesterday = new Date(Date.now() - 86400000).toISOString().split('T')[0];

    if (dateStr === today) return 'Today';
    if (dateStr === yesterday) return 'Yesterday';
    return 'Earlier';
  }

  function showToast(notification: Notification) {
    // Integration with your toast notification system
    console.log('Toast:', notification.title, notification.body);
  }

  function markAsRead(notificationId: string) {
    const notification = notifications.value.find(n => n.id === notificationId);
    if (notification) {
      notification.read = true;
      persistState();
    }
  }

  function markAllAsRead() {
    notifications.value.forEach(n => n.read = true);
    persistState();
  }

  function persistState() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify({
      notifications: notifications.value,
      page: currentPage.value,
    }));
  }

  function loadPersistedState() {
    const stored = localStorage.getItem(STORAGE_KEY);
    if (stored) {
      const data = JSON.parse(stored);
      notifications.value = data.notifications || [];
      currentPage.value = data.page || 1;
    }
  }

  function loadMore() {
    if (hasMore.value) {
      currentPage.value++;
      persistState();
    }
  }

  return {
    // State
    notifications,
    isConnected,
    // Computed
    unreadCount,
    groupedNotifications,
    paginatedNotifications,
    hasMore,
    // Actions
    initializeSocket,
    markAsRead,
    markAllAsRead,
    loadMore,
    loadPersistedState,
  };
});
```



## Common Mistakes

- Asking vague questions like 'Can you help with the code?' without specifying what kind of help or which file
- Providing zero context and expecting Claude to understand your project's architecture or coding standards
- Asking for multiple unrelated tasks in a single prompt instead of breaking them into separate focused requests
- Expecting perfect code on the first try and abandoning the process when it needs refinement
- Stating solutions instead of problems (e.g., 'Use a for loop' instead of 'I need to iterate over this array')
- Forgetting to specify the output format, file location, or implementation details you expect
- Not sharing relevant existing code or patterns that Claude should follow
- Overloading prompts with excessive context that buries the actual request
- Assuming Claude remembers previous conversations or project context between sessions
- Neglecting to mention constraints like performance requirements, browser compatibility, or security needs


## Best Practices

- Always specify your technology stack, framework version, and relevant file paths in initial requests
- Provide 2-3 lines of existing code as a style reference when you want Claude to match your patterns
- Use the SCOPE method (Situation, Complication, Objective, Parameters, Expectations) to structure complex requests
- Embrace iteration—plan for 2-3 rounds of refinement before considering a request complete
- Break large refactoring tasks into phases: analysis first, then implementation one phase at a time
- State constraints explicitly (performance, security, compatibility) rather than assuming they'll be considered
- Ask for explanations alongside code when learning new patterns or when correctness is critical
- Reference specific files or functions you want Claude to maintain consistency with
- After receiving code, always verify it matches your expectations before moving to the next task
- When results are unexpected, provide specific feedback about what needs adjustment rather than restarting

