```python
// Example 3: Self-Verification Techniques
// Claude Code uses these techniques to validate its own output

// Self-verification helper functions
const SelfVerifier = {
  // 1. Syntax Validation: Check for common syntax errors
  validateSyntax(code) {
    const errors = [];

    // Check for balanced braces
    const openBraces = (code.match(/\{/g) || []).length;
    const closeBraces = (code.match(/\}/g) || []).length;
    if (openBraces !== closeBraces) {
      errors.push(`Unbalanced braces: ${openBraces} { vs ${closeBraces} }`);
    }

    // Check for balanced parentheses
    const openParens = (code.match(/\(/g) || []).length;
    const closeParens = (code.match(/\)/g) || []).length;
    if (openParens !== closeParens) {
      errors.push(`Unbalanced parentheses: ${openParens} ( vs ${closeParens} )`);
    }

    return {
      isValid: errors.length === 0,
      errors
    };
  },

  // 2. Type Checking: Validate type consistency
  checkTypes(fn, testInputs) {
    const results = [];

    testInputs.forEach(({ input, expectedType }) => {
      const actualType = typeof input;
      const matches = actualType === expectedType;
      results.push({ input, expectedType, actualType, matches });
    });

    const allMatch = results.every(r => r.matches);
    return { isValid: allMatch, results };
  },

  // 3. Logic Review: Verify logic against known cases
  verifyLogic(fn, knownCases) {
    const failures = [];

    knownCases.forEach(testCase => {
      try {
        const result = fn(testCase.input);
        const passed = JSON.stringify(result) === JSON.stringify(testCase.expected);
        if (!passed) {
          failures.push({
            input: testCase.input,
            expected: testCase.expected,
            got: result
          });
        }
      } catch (error) {
        failures.push({
          input: testCase.input,
          error: error.message
        });
      }
    });

    return {
      isValid: failures.length === 0,
      failures
    };
  },

  // 4. Sanity Check: Quick validation with simple cases
  sanityCheck(fn) {
    const simpleCases = [
      { input: null, shouldFail: true },
      { input: undefined, shouldFail: true },
      { input: 0, shouldWork: true },
      { input: "test", shouldWork: true }
    ];

    const issues = [];

    simpleCases.forEach(testCase => {
      try {
        const result = fn(testCase.input);
        if (testCase.shouldFail && result !== false && result !== null) {
          issues.push(`${testCase.input} should return false/null but got ${result}`);
        }
      } catch (error) {
        if (!testCase.shouldFail) {
          issues.push(`Unexpected error for ${testCase.input}: ${error.message}`);
        }
      }
    });

    return { isValid: issues.length === 0, issues };
  }
};

// Example usage: Verify a string formatting function
function formatUsername(firstName, lastName) {
  if (!firstName || !lastName) return null;
  return `${firstName.charAt(0).toUpperCase()}. ${lastName}`;
}

console.log("Self-Verification Example: formatUsername\n");
console.log("=".repeat(50));

// Run all verification checks
const codeToVerify = "function formatUsername(firstName, lastName) { ... }";

console.log("\n1. Syntax Validation:");
const syntaxResult = SelfVerifier.validateSyntax(codeToVerify);
console.log(`   Status: ${syntaxResult.isValid ? '✓ Passed' : '✗ Failed'}`);
if (!syntaxResult.isValid) console.log(`   Errors: ${syntaxResult.errors.join(', ')}`);

console.log("\n2. Logic Verification:");
const logicResult = SelfVerifier.verifyLogic(formatUsername, [
  { input: ["John", "Doe"], expected: "J. Doe" },
  { input: ["jane", "Smith"], expected: "J. Smith" },
  { input: [null, "Doe"], expected: null },
  { input: ["John", null], expected: null }
]);
console.log(`   Status: ${logicResult.isValid ? '✓ Passed' : '✗ Failed'}`);
if (!logicResult.isValid) {
  console.log("   Failed cases:");
  logicResult.failures.forEach(f => console.log(`   - Input: ${f.input}, Expected: ${f.expected}, Got: ${f.got}`));
}

console.log("\n3. Sanity Check:");
const sanityResult = SelfVerifier.sanityCheck(formatUsername);
console.log(`   Status: ${sanityResult.isValid ? '✓ Passed' : '✗ Failed'}`);
if (!sanityResult.isValid) {
  console.log("   Issues:");
  sanityResult.issues.forEach(i => console.log(`   - ${i}`));
}

console.log("\n" + "=".repeat(50));
console.log("\nSelf-Verification Complete!");
console.log("Use these techniques before presenting code to ensure quality.");
```



## Common Mistakes

- Writing tests after code is generated without providing test specifications upfront, leading to tests that only confirm what the code does rather than validating intended behavior
- Ignoring test failure output and assuming the code is correct because most tests pass, missing critical edge cases that failed
- Focusing only on happy path tests and neglecting edge cases, error conditions, and boundary values that cause real-world failures
- Writing tests that are too coupled to implementation details, causing test failures when refactoring even though functionality remains correct
- Not interpreting test results holistically—stopping after seeing a pass/fail status without analyzing patterns, execution times, or error messages
- Relying solely on self-verification without external test suites, missing issues that automated testing would catch
- Creating test cases that overlap significantly or test the same code paths multiple times while leaving other paths completely untested


## Best Practices

- Provide test specifications alongside your requirements before generation, clearly defining expected behavior, edge cases, and acceptance criteria
- Run test suites immediately after receiving generated code, interpreting results fully before proceeding to avoid propagating bugs
- Balance test coverage across happy paths, edge cases, error handling, and performance to catch diverse issue categories
- Use self-verification as a preliminary check (syntax, types, basic logic) but complement it with comprehensive external test suites
- When tests fail, provide specific feedback about what went wrong and what the expected behavior should be, enabling Claude Code to make targeted improvements
- Regularly review test coverage to identify gaps and ensure critical paths are tested, especially for complex business logic
- Treat test failures as learning opportunities—both for refining the immediate solution and improving future interactions with Claude Code

