  // Happy path tests
  {
    input: "user@example.com",
    expected: true,
    description: "Standard valid email"
  },
  {
    input: "test.user@domain.co.uk",
    expected: true,
    description: "Email with subdomain and dot"
  },
  {
    input: "user+tag@gmail.com",
    expected: true,
    description: "Email with plus addressing"
  },
  // Edge case tests
  {
    input: "",
    expected: false,
    description: "Empty string should fail"
  },
  {
    input: "no-at-sign",
    expected: false,
    description: "Missing @ symbol"
  },
  {
    input: "@no-local-part.com",
    expected: false,
    description: "Missing local part"
  },
  {
    input: "no-domain@",
    expected: false,
    description: "Missing domain"
  }
];

