        return true;
      }
    }
  ]
};

// Test runner function
function runTestSuite(suite) {
  console.log(`\nRunning Test Suite: ${suite.name}\n`);
  console.log("-".repeat(50));

  const results = {
    passed: 0,
    failed: 0,
    failures: []
  };

  const startTime = Date.now();

  suite.tests.forEach((test, index) => {
    try {
      test.fn();
      results.passed++;
      console.log(`✓ ${test.name}`);
    } catch (error) {
      results.failed++;
      results.failures.push({
        testName: test.name,
        error: error.message
      });
      console.log(`✗ ${test.name}`);
      console.log(`  Error: ${error.message}`);
    }
  });

  const duration = Date.now() - startTime;

  console.log("-".repeat(50));
  console.log(`\nTest Suite Summary:`);
  console.log(`  Total Tests: ${suite.tests.length}`);
  console.log(`  Passed: ${results.passed}`);
  console.log(`  Failed: ${results.failed}`);
  console.log(`  Duration: ${duration}ms`);

  // Interpretation guidance
  console.log(`\nInterpretation Guide:`);
  if (results.failed === 0) {
    console.log(`  ✓ All tests passed. The code meets quality standards.`);
  } else {
    const failureRate = ((results.failed / suite.tests.length) * 100).toFixed(1);
    console.log(`  ⚠️  ${failureRate}% failure rate detected.`);
    console.log(`  Action: Review failed tests and provide feedback to refine the solution.`);
  }

  return results;
}

// Execute the test suite
